}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *wall,
                int *src,
                int *results,
                int cols, 
                int rows,
                int startStep,
                int border)
{
    // This function simulates the CUDA kernel with OpenMP parallelization.
    // We will parallelize over blocks and threads within blocks.
    // Each block processes BLOCK_SIZE threads.
    // The kernel uses shared memory in CUDA; here we use local arrays per thread team.

    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blockCols = (cols + small_block_cols - 1) / small_block_cols;

    // Parallelize over blocks
    #pragma omp parallel
    {
        int prev[BLOCK_SIZE];
        int result_arr[BLOCK_SIZE];

        #pragma omp for schedule(static)
        for (int bx = 0; bx < blockCols; bx++) {
            int blkX = small_block_cols * bx - border;
            int blkXmax = blkX + BLOCK_SIZE - 1;

            // Load prev array
            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int xidx = blkX + tx;
                if (IN_RANGE(xidx, 0, cols - 1)) {
                    prev[tx] = src[xidx];
                } else {
                    prev[tx] = 0; // or some default value
                }
            }

            // Synchronize threads in block (implicit in OpenMP for loop)
            // Compute iterations
            for (int i = 0; i < iteration; i++) {
                #pragma omp parallel for
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int xidx = blkX + tx;
                    int validXmin = (blkX < 0) ? -blkX : 0;
                    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

                    int W = tx - 1;
                    int E = tx + 1;

                    W = (W < validXmin) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    bool isValid = IN_RANGE(tx, validXmin, validXmax);

                    if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                        int left = prev[W];
                        int up = prev[tx];
                        int right = prev[E];
                        int shortest = MIN(left, up);
                        shortest = MIN(shortest, right);
                        int index = cols * (startStep + i) + xidx;
                        result_arr[tx] = shortest + wall[index];
                    }
                }
                // Synchronize threads in block (implicit)
                if (i == iteration - 1)
                    break;
                // Update prev for next iteration
                #pragma omp parallel for
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int xidx = blkX + tx;
                    int validXmin = (blkX < 0) ? -blkX : 0;
                    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

                    int W = tx - 1;
                    int E = tx + 1;

                    W = (W < validXmin) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    bool isValid = IN_RANGE(tx, validXmin, validXmax);

                    if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                        prev[tx] = result_arr[tx];
                    }
                }
            }

            // Write results back
            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int xidx = blkX + tx;
                int validXmin = (blkX < 0) ? -blkX : 0;
                int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

                int W = tx - 1;
                int E = tx + 1;

                W = (W < validXmin) ? validXmin : W;
                E = (E > validXmax) ? validXmax : E;

                bool isValid = IN_RANGE(tx, validXmin, validXmax);

                if (IN_RANGE(tx, iteration, BLOCK_SIZE - iteration - 1) && isValid) {
                    results[xidx] = result_arr[tx];
                }
            }
        }
    }
}

int calc_path(int *wall, int *result[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;
    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;
        dynproc_kernel(
            MIN(pyramid_height, rows - t - 1),
            wall, result[src], result[dst],
            cols, rows, t, borderCols);
    }
    return dst;
}

int main(int argc, char** argv)
{
    run(argc,argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*HALO*2;
    int blockCols = cols/smallBlockCol+((cols%smallBlockCol==0)?0:1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int size = rows*cols;

    int *gpuWall = new int[size - cols];
    int *gpuResult[2];
    gpuResult[0] = new int[cols];
    gpuResult[1] = new int[cols];

    // Copy initial data to gpuResult[0] and gpuWall
    for (int i = 0; i < cols; i++) {
        gpuResult[0][i] = data[i];
    }
    for (int i = 0; i < size - cols; i++) {
        gpuWall[i] = data[cols + i];
    }

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, \
	 pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy result back
    for (int i = 0; i < cols; i++) {
        result[i] = gpuResult[final_ret][i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] gpuWall;
    delete [] gpuResult[0];
    delete [] gpuResult[1];

    delete [] data;
    delete [] wall;
    delete [] result;

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
